mapper.sql:
WHERE O.ACTIVITY != 0

    AND O.PAY_SCHEDULE_NO = #{payScheduleNo, jdbcType=VARCHAR}


    AND O.INCLUDE_TYPE = #{includeType, jdbcType=NUMERIC}


    AND E.EMP_OFFICE = #{empOfficeCond, jdbcType=VARCHAR}


    AND (O.EMPID LIKE '%' || #{empSearch, jdbcType=VARCHAR} || '%'
      OR CONVERTTOUNSIGN(UPPER(E.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{empSearch, jdbcType=VARCHAR})) || '%')

mapper.select:
SELECT COUNT(1)
FROM PA_PAY_OBJECT
WHERE PAY_SCHEDULE_NO = #{payScheduleNo, jdbcType=VARCHAR}
  AND EMPID            = #{empId,         jdbcType=VARCHAR}
